<?php
/**
 * AJAX: Get Exam Results
 * 
 * @author School ERP Development Team
 * @version 1.0.0
 */

// Start output buffering FIRST to catch any unwanted output
ob_start();

require_once '../../config/config.php';

// NOW suppress error display AFTER config is loaded
error_reporting(E_ALL);
ini_set('display_errors', 0);
ini_set('display_startup_errors', 0);

// Clear any output that might have been generated by config.php
ob_clean();

// Set JSON header early
header('Content-Type: application/json; charset=utf-8');
header('Cache-Control: no-cache, must-revalidate');

// Support both session-based (web) and user_id parameter (Flutter/mobile) authentication
$currentUser = null;
$userId = $_GET['user_id'] ?? $_POST['user_id'] ?? null;

if ($userId) {
    // Flutter/mobile app authentication
    $sql = "SELECT u.*, r.role_name, b.branch_name 
            FROM users u 
            LEFT JOIN roles r ON u.role_id = r.id 
            LEFT JOIN branches b ON u.branch_id = b.id 
            WHERE u.id = ? AND u.is_active = 1";
    $stmt = executeQuery($sql, 'i', [$userId]);
    $currentUser = fetchOne($stmt);
    
    if (!$currentUser) {
        jsonResponse(false, 'Invalid user ID');
        exit;
    }
    
    // Set session for compatibility
    $_SESSION['user_id'] = $currentUser['id'];
    $_SESSION['role_name'] = $currentUser['role_name'];
} else {
    // Web session-based authentication
    if (!isLoggedIn()) {
        jsonResponse(false, 'Unauthorized');
        exit;
    }
    $currentUser = getCurrentUser();
}

$examId = $_GET['exam_id'] ?? null;
$studentId = $_GET['student_id'] ?? null;
$classId = $_GET['class_id'] ?? null;

try {
    $currentSession = getCurrentSession();
    $sessionId = $currentSession['id'] ?? null;
    
    // If student view, get their student record
    if ($currentUser['role_name'] === 'Student' && !$studentId) {
        $student = getStudentByUserId($currentUser['id']);
        if ($student) {
            $studentId = $student['id'];
        }
    }
    
    // Build query to get results
    if ($studentId) {
        // Get results for a specific student
        $sql = "SELECT 
                e.id as exam_id, e.exam_name, e.class_id, c.class_name,
                s.id as student_id, CONCAT(s.first_name, ' ', s.last_name) as student_name,
                es.subject_id, sub.subject_name, sub.subject_code,
                es.total_marks, sm.marks_obtained, es.passing_marks,
                CASE WHEN sm.marks_obtained IS NULL THEN 0 ELSE sm.marks_obtained END as obtained_marks,
                CASE WHEN sm.is_absent = 1 THEN 0 ELSE 1 END as is_pass
                FROM exams e
                INNER JOIN classes c ON e.class_id = c.id
                INNER JOIN exam_schedule es ON e.id = es.exam_id
                INNER JOIN subjects sub ON es.subject_id = sub.id
                LEFT JOIN student_marks sm ON es.id = sm.exam_schedule_id AND sm.student_id = ?
                INNER JOIN students s ON s.id = ?
                WHERE s.id = ?";
        
        $params = [$studentId, $studentId, $studentId];
        $types = 'iii';
        
        if ($examId) {
            $sql .= " AND e.id = ?";
            $params[] = $examId;
            $types .= 'i';
        }
        
        if ($sessionId) {
            $sql .= " AND e.session_id = ?";
            $params[] = $sessionId;
            $types .= 'i';
        }
        
        $sql .= " ORDER BY e.start_date DESC, sub.subject_name";
        
        $stmt = executeQuery($sql, $types, $params);
        $rows = fetchAll($stmt);
        
        // Group by exam
        $results = [];
        $examGroups = [];
        
        foreach ($rows as $row) {
            $examKey = $row['exam_id'];
            if (!isset($examGroups[$examKey])) {
                $examGroups[$examKey] = [
                    'exam_id' => $row['exam_id'],
                    'exam_name' => $row['exam_name'],
                    'student_id' => $row['student_id'],
                    'student_name' => $row['student_name'],
                    'class_id' => $row['class_id'],
                    'class_name' => $row['class_name'],
                    'subjects' => [],
                ];
            }
            
            $percentage = $row['total_marks'] > 0 
                ? ($row['obtained_marks'] / $row['total_marks']) * 100 
                : 0;
            
            // Calculate grade (simplified)
            $grade = 'F';
            if ($percentage >= 90) $grade = 'A+';
            elseif ($percentage >= 80) $grade = 'A';
            elseif ($percentage >= 70) $grade = 'B';
            elseif ($percentage >= 60) $grade = 'C';
            elseif ($percentage >= 50) $grade = 'D';
            elseif ($percentage >= 40) $grade = 'E';
            
            $examGroups[$examKey]['subjects'][] = [
                'subject_id' => $row['subject_id'],
                'subject_name' => $row['subject_name'],
                'subject_code' => $row['subject_code'],
                'total_marks' => $row['total_marks'],
                'obtained_marks' => $row['obtained_marks'],
                'percentage' => round($percentage, 2),
                'grade' => $grade,
                'is_pass' => $row['is_pass'] == 1 && $row['obtained_marks'] >= $row['passing_marks'],
            ];
        }
        
        // Calculate totals and ranks
        foreach ($examGroups as $examKey => &$exam) {
            $totalMarks = 0;
            $obtainedMarks = 0;
            
            foreach ($exam['subjects'] as $subject) {
                $totalMarks += $subject['total_marks'];
                $obtainedMarks += $subject['obtained_marks'];
            }
            
            $exam['total_marks'] = $totalMarks;
            $exam['obtained_marks'] = $obtainedMarks;
            $exam['percentage'] = $totalMarks > 0 ? round(($obtainedMarks / $totalMarks) * 100, 2) : 0;
            
            // Calculate overall grade
            $overallGrade = 'F';
            if ($exam['percentage'] >= 90) $overallGrade = 'A+';
            elseif ($exam['percentage'] >= 80) $overallGrade = 'A';
            elseif ($exam['percentage'] >= 70) $overallGrade = 'B';
            elseif ($exam['percentage'] >= 60) $overallGrade = 'C';
            elseif ($exam['percentage'] >= 50) $overallGrade = 'D';
            elseif ($exam['percentage'] >= 40) $overallGrade = 'E';
            
            $exam['grade'] = $overallGrade;
            $exam['rank'] = 0; // Rank calculation would require comparing with all students
        }
        
        $results = array_values($examGroups);
        
    } else {
        // Get results for a class/exam
        $sql = "SELECT 
                e.id as exam_id, e.exam_name, e.class_id, c.class_name,
                s.id as student_id, CONCAT(s.first_name, ' ', s.last_name) as student_name,
                es.subject_id, sub.subject_name, sub.subject_code,
                es.total_marks, sm.marks_obtained, es.passing_marks
                FROM exams e
                INNER JOIN classes c ON e.class_id = c.id
                INNER JOIN exam_schedule es ON e.id = es.exam_id
                INNER JOIN subjects sub ON es.subject_id = sub.id
                INNER JOIN students s ON s.current_class_id = e.class_id AND s.status = 'Active'
                LEFT JOIN student_marks sm ON es.id = sm.exam_schedule_id AND sm.student_id = s.id
                WHERE 1=1";
        
        $params = [];
        $types = '';
        
        if ($examId) {
            $sql .= " AND e.id = ?";
            $params[] = $examId;
            $types .= 'i';
        }
        
        if ($classId) {
            $sql .= " AND e.class_id = ?";
            $params[] = $classId;
            $types .= 'i';
        }
        
        if ($sessionId) {
            $sql .= " AND e.session_id = ?";
            $params[] = $sessionId;
            $types .= 'i';
        }
        
        $sql .= " ORDER BY e.start_date DESC, s.first_name, s.last_name, sub.subject_name";
        
        $stmt = executeQuery($sql, $types, $params);
        $rows = fetchAll($stmt);
        
        // Group by exam and student
        $results = [];
        $examStudentGroups = [];
        
        foreach ($rows as $row) {
            $key = $row['exam_id'] . '_' . $row['student_id'];
            if (!isset($examStudentGroups[$key])) {
                $examStudentGroups[$key] = [
                    'exam_id' => $row['exam_id'],
                    'exam_name' => $row['exam_name'],
                    'student_id' => $row['student_id'],
                    'student_name' => $row['student_name'],
                    'class_id' => $row['class_id'],
                    'class_name' => $row['class_name'],
                    'subjects' => [],
                ];
            }
            
            $obtainedMarks = $row['marks_obtained'] ?? 0;
            $percentage = $row['total_marks'] > 0 
                ? ($obtainedMarks / $row['total_marks']) * 100 
                : 0;
            
            $grade = 'F';
            if ($percentage >= 90) $grade = 'A+';
            elseif ($percentage >= 80) $grade = 'A';
            elseif ($percentage >= 70) $grade = 'B';
            elseif ($percentage >= 60) $grade = 'C';
            elseif ($percentage >= 50) $grade = 'D';
            elseif ($percentage >= 40) $grade = 'E';
            
            $examStudentGroups[$key]['subjects'][] = [
                'subject_id' => $row['subject_id'],
                'subject_name' => $row['subject_name'],
                'subject_code' => $row['subject_code'],
                'total_marks' => $row['total_marks'],
                'obtained_marks' => $obtainedMarks,
                'percentage' => round($percentage, 2),
                'grade' => $grade,
                'is_pass' => $obtainedMarks >= $row['passing_marks'],
            ];
        }
        
        // Calculate totals
        foreach ($examStudentGroups as &$result) {
            $totalMarks = 0;
            $obtainedMarks = 0;
            
            foreach ($result['subjects'] as $subject) {
                $totalMarks += $subject['total_marks'];
                $obtainedMarks += $subject['obtained_marks'];
            }
            
            $result['total_marks'] = $totalMarks;
            $result['obtained_marks'] = $obtainedMarks;
            $result['percentage'] = $totalMarks > 0 ? round(($obtainedMarks / $totalMarks) * 100, 2) : 0;
            
            $overallGrade = 'F';
            if ($result['percentage'] >= 90) $overallGrade = 'A+';
            elseif ($result['percentage'] >= 80) $overallGrade = 'A';
            elseif ($result['percentage'] >= 70) $overallGrade = 'B';
            elseif ($result['percentage'] >= 60) $overallGrade = 'C';
            elseif ($result['percentage'] >= 50) $overallGrade = 'D';
            elseif ($result['percentage'] >= 40) $overallGrade = 'E';
            
            $result['grade'] = $overallGrade;
            $result['rank'] = 0;
        }
        
        $results = array_values($examStudentGroups);
    }
    
    jsonResponse(true, 'Results loaded', $results);
    
} catch (Exception $e) {
    jsonResponse(false, 'Failed to load results: ' . $e->getMessage());
}

